export interface IndicatorData {
    left: number;
    width?: number | string;
    right?: number;
}
/**
 * инкапсулирует логику управления положением индикатора табов
 *
 * его рассчеты также использованы для работы анимации
 *
 * Для работы анимации элементу необходимо задать transition для свойств width, left и right,
 * а также логически управлять данными текущего и предыдущего табов, логика такая
 *
 * 1. При клике таб сразу становится текущим
 * 2. В этот момент индикатор займет все пространство между предыдущм и текущим табами, хук сам сделает математику и т.д
 * 3. Через определенное время (тайминг анимации) предыдущий таб тоже становиться текущим
 * 4. В этот момент индикатор станет размером с текущий таб
 * 5. Анимация завершена, вы восхитительны
 *
 * Обратите внимание на 2 важные вещи:
 *
 * 1. тайминг transition в css должен быть немного (примерно в полтора раза) больше задержки присваивания предыдущему табу данных целевого
 * это позволяет сделать анимацию менее линейной, т.к индикатор начинает "уходить" с изначального таба еще до того как дополз до целевого
 * 2. общий тайминг анимации будет равен сумме двух тамингов, т.к по факту размер изменяется 2 раза (сначала увеличивается, потом уменьшается),
 * но уменьшение начинается раньше чем закончится увеличение
 *
 * Также обработаны кейсы первой отрисовки (когда предыдущего таба еще нет) и отсутствия данных (когда вообще нет выбранного таба)
 *
 * @param currentTabElement див текущего выбранного таба
 * @param previousTabElement див предыдущего выбранного таба
 * @param tabsContainer див контейнера с табами
 * @param scrollLeft проскроленное слева расстояние, нужно для компенсации визуального положения таба
 *
 * @returns объект с данными для абсолютного позиционирования индикатора
 */
export declare const useTabsIndicator: (currentTabElement: HTMLDivElement, previousTabElement: HTMLDivElement, tabsContainer: HTMLDivElement | null, scrollLeft: number) => IndicatorData;
